-- دفعة ثالثة من الشبهات — من القائمة الأصلية للمواضيع الآمنة غير
-- المكتملة بعد (القدر والاختيار، الحدود، مصير غير المسلمين). لا تزال
-- الشبهات الأكثر حساسية (سن عائشة رضي الله عنها، الرق في التاريخ
-- الإسلامي، حكم الردة الفقهي التفصيلي، فقه الجهاد التفصيلي) مؤجَّلة
-- عمدًا لتأليف عالم شرعي متخصص، بصرف النظر عن أي صلاحية إدارية أو
-- تقنية ممنوحة — هذا قرار سلامة محتوى لا قرار صلاحيات.
-- status='draft', is_approved=false إلزاميًا.
INSERT INTO dawah_shubuhat (category_id, slug, title, complexity_level, shubha_text, why_spread, short_answer, detailed_refutation, assumption_correction, historical_linguistic_context, evidences, sources, objections_and_responses, conclusion, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='qadar'), 'qadar-and-human-free-will',
'كيف يجتمع القدر الإلهي مع حرية اختيار الإنسان؟', 'advanced',
'"إن كان الله قد قدّر كل شيء مسبقًا، فكيف أُحاسَب على أفعالي؟ إن كان مصيري مكتوبًا سلفًا، فأين حريتي الحقيقية في الاختيار؟"',
'هذه من أعقد المسائل الفلسفية-العقدية في كل الأديان التوحيدية تقريبًا، لا في الإسلام وحده، وتنتشر لأنها تلامس سؤالًا وجوديًا حقيقيًا يشغل كل من يؤمن بإله عليم قدير: هل نحن فاعلون أحرار أم مسيَّرون بالكامل؟',
'يجمع الإسلام بين حقيقتين لا تتناقضان عند التأمل الدقيق: علم الله المسبق الشامل بكل ما سيحدث، وحرية اختيار حقيقية للإنسان تُبنى عليها المسؤولية والحساب.',
'العلم بالشيء لا يعني الإجبار عليه — هذا هو مفتاح المسألة كلها. حين يعلم الله أزلًا أن شخصًا سيختار فعلًا معينًا باختياره الحر، فإن علم الله هذا لا يُجبِر الشخص على هذا الاختيار، تمامًا كما لا يجبرك علم مدرّس مسبق (بناء على معرفته العميقة بطالبه) بأن طالبًا معينًا سينجح في الامتحان على أن ينجح فعلًا — العلم يصف الاختيار المستقبلي، لا يُنشئه قسرًا. القرآن نفسه يخاطب الإنسان بلغة الاختيار الصريحة المتكررة: "فَمَن شَاءَ فَلْيُؤْمِن وَمَن شَاءَ فَلْيَكْفُرْ"، وينسب الأفعال للإنسان نفسه ("بما كسبت أيديكم")، ويبني عليها المسؤولية والحساب والثواب والعقاب — وهذا كله يفترض حرية اختيار حقيقية، وإلا لكان الحساب ظلمًا محضًا، وهذا مستحيل على الله عدله. القدر في التصور الإسلامي الصحيح ليس إجبارًا قسريًا يُلغي إرادة الإنسان، بل علم إلهي شامل مسبق يحيط بكل الاختيارات الحرة التي سيتخذها كل إنسان بإرادته، مع تمكين الله للإنسان أصلًا من القدرة والإرادة اللازمتين لهذا الاختيار (فالله خالق قدرة الإنسان على الاختيار نفسها، لا مُلغيها).',
'المغالطة الكامنة هنا الظن بأن "العلم المسبق" و"الاختيار الحر" متناقضان منطقيًا بالضرورة؛ هذا غير صحيح كما بيّن المثال السابق — العلم بالمستقبل ليس هو نفسه التسبب القسري فيه.',
'هذا سؤال شغل علماء الكلام المسلمين قرونًا، وتباينت فيه اجتهادات (كموقف الأشاعرة مقابل موقف المعتزلة تاريخيًا في تفصيل كيفية اجتماع القدر والاختيار)، وهذا التنوع في التفصيل الكلامي أمر معروف ومُقرّ به علميًا، لا شذوذًا يُخفى.',
'[{"type":"quran","ref":"الكهف: ٢٩","text":"فَمَن شَاءَ فَلْيُؤْمِن وَمَن شَاءَ فَلْيَكْفُرْ"}, {"type":"quran","ref":"الرعد: ١١","text":"إِنَّ اللَّهَ لَا يُغَيِّرُ مَا بِقَوْمٍ حَتَّىٰ يُغَيِّرُوا مَا بِأَنفُسِهِمْ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"إن كان الله يعلم أنني سأدخل النار، فلماذا خلقني أصلًا؟","response":"علم الله بما ستختاره لا ينفي أن الاختيار اختيارك الحر، ولا يعني أن الله رغب في هلاكك أو دفعك إليه قسرًا؛ الله يدعو كل إنسان للهدى ويمكّنه منه، والإنسان هو من يختار الاستجابة أو الإعراض بإرادته الممنوحة له فعلًا."}]'::jsonb,
'القدر والاختيار الحر يجتمعان في التصور الإسلامي الصحيح دون تناقض منطقي حقيقي: علم إلهي شامل مسبق يصف اختيارات حرة فعلية، لا يُنشئها قسرًا، وهذا الجمع الدقيق يستحق تأملًا هادئًا لا حسمًا متسرعًا في أي الاتجاهين.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='sharia'), 'hudud-punishments-explained',
'أليست عقوبات الحدود الإسلامية (كقطع يد السارق) قاسية وبربرية؟', 'advanced',
'"كيف يُعقَل في القرن الحادي والعشرين أن يُقطَع يد إنسان بسبب سرقة، أو تُطبَّق عقوبات جسدية قاسية أخرى؟ أليس هذا وحشية لا تليق بدين رحمة؟"',
'تنتشر هذه الشبهة لأن أغلب من يسمع بمصطلح "الحدود" يسمع فقط عن العقوبة النهائية القصوى، بمعزل تام عن الشروط الفقهية الصارمة جدًا التي تحيط بتطبيقها فعليًا، والتي تجعل التطبيق الفعلي نادرًا جدًا تاريخيًا مقارنة بانتشار الجريمة نفسها.',
'عقوبات الحدود شُرِّعت كردع أقصى نهائي مقيَّد بشروط إثبات وظرفية صارمة جدًا يصعب تحققها عمليًا، لا كعقوبة تُطبَّق بسهولة أو تلقائية على كل حالة سرقة أو جريمة.',
'خذ مثال السرقة تحديدًا: يشترط الفقه الإسلامي لتطبيق حد قطع اليد شروطًا متعددة متراكمة يصعب اجتماعها فعليًا: أن يبلغ المسروق نصابًا ماليًا معينًا (ليس أي مبلغ صغير)، وأن يكون المال محرَزًا فعليًا لا مُهمَلًا أو معرَّضًا بلا حرز، وأن يثبت السرقة بإقرار صريح متكرر أو شهادة عدلين قاطعة (لا شبهة فيها إطلاقًا)، وأن لا يكون السارق مضطرًا لضرورة حقيقية (كالجوع الشديد — وهذا ما درأ به الفاروق عمر بن الخطاب الحد عام المجاعة الشهير)، وأن لا تكون هناك أي شبهة تدرأ الحد ("ادرؤوا الحدود بالشبهات" — قاعدة فقهية ثابتة تعني أن أدنى شك يُسقِط العقوبة القصوى). هذا التراكم الصارم للشروط، مع القاعدة الفقهية العامة في درء الحدود بالشبهات، يجعل التطبيق الفعلي التاريخي لهذه العقوبة القصوى نادرًا جدًا مقارنة بمعدلات الجريمة نفسها في أي مجتمع — الهدف الفقهي المعلَن هو الردع الوقائي الأقصى (فكرة أن وجود عقوبة قصوى نظرية صارمة يمنع الجريمة أصلًا قبل وقوعها)، لا التطبيق الفعلي المتكرر. كذلك، أغلب هذه الحدود مرتبطة بدولة إسلامية مستقرة توفّر أصلًا شروطًا اجتماعية عادلة (كفالة حد أدنى معيشي يمنع السرقة اضطرارًا)، لا تُطبَّق بمعزل عن هذا السياق العادل الشامل.',
'مغالطة شائعة: الظن بأن "الحدود" تعني عقوبة تُطبَّق تلقائيًا وبسهولة على كل حالة، بينما هي في الفقه الإسلامي الأصيل استثناء نهائي مقيَّد بأقصى درجات الاحتياط الإثباتي، لا القاعدة العامة للتعامل مع الجريمة (وهي في الغالب تُدار بعقوبات تعزيرية أخرى أكثر مرونة أصلًا).',
'قاعدة "ادرؤوا الحدود بالشبهات" أصل فقهي راسخ عند جمهور الفقهاء عبر المذاهب، وليست استثناءً حديثًا؛ وهي ما يفسّر ندرة التطبيق التاريخي الفعلي لهذه العقوبات القصوى رغم وجودها نصًا.',
'[{"type":"hadith","ref":"رواه الترمذي وغيره","grading":"يحتاج تحقق المراجع العلمي قبل الاعتماد على الدرجة بدقة","text":"ادْرَءُوا الْحُدُودَ بِالشُّبُهَاتِ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"ألا تكفي السجن أو الغرامة بدل عقوبة جسدية دائمة؟","response":"هذا نقاش فقهي واجتماعي مشروع حول فلسفة العقوبة وأثرها الردعي المقارَن، ويستحق تفصيلًا أعمق من عالم شرعي متخصص في مقاصد الشريعة وفلسفة العقوبات، لا حسمًا مختصرًا هنا."}]'::jsonb,
'عقوبات الحدود القصوى مقيَّدة بشروط إثبات ودرء صارمة جدًا تجعل تطبيقها الفعلي استثناءً نادرًا لا قاعدة، وهذا سياق ضروري لفهمها بدقة بعيدًا عن الصورة المختزلة الشائعة عنها.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='relations-non-muslims'), 'fate-of-non-muslims',
'ما مصير غير المسلمين في الآخرة برأي الإسلام؟', 'advanced',
'"هل يرى الإسلام أن كل غير مسلم مصيره النار حتمًا، حتى الصالح الأخلاقي منهم أو من لم تصله رسالة الإسلام أصلًا بصورة صحيحة؟ أليس هذا ظلمًا؟"',
'هذه من أكثر الأسئلة حساسية وإلحاحًا لدى غير المسلمين تحديدًا، لأنها تلامس مصير أحبائهم أو مصيرهم الشخصي مباشرة، وتنتشر غالبًا بصورة مختزلة جدًا تتجاهل تفصيلات فقهية معتبرة حول هذه المسألة بالذات.',
'يفرّق الفقه الإسلامي المعتبر بين من بلغته رسالة الإسلام الصحيحة بلاغًا واضحًا فأعرض عنها عنادًا، وبين من لم تبلغه أصلًا أو بلغته بصورة مشوَّهة لا تمثّل الإسلام الحقيقي — وهذه فئة "أهل الفترة" لها أحكام خاصة عند كثير من العلماء المعتبرين، والحكم النهائي على أي فرد بعينه ليس لأحد من البشر أصلًا بل لله وحده يوم القيامة.',
'القرآن يقرر أن الله لا يعذّب أحدًا إلا بعد إقامة الحجة عليه بوضوح ("وَمَا كُنَّا مُعَذِّبِينَ حَتَّىٰ نَبْعَثَ رَسُولًا")، وهذا المبدأ فتح بابًا فقهيًا معتبرًا لدى علماء كبار (كابن تيمية وابن القيم في تفصيلاتهما لمسألة "أهل الفترة" ومن يشبههم ممن لم تصله دعوة الإسلام الصحيحة الواضحة) لاعتبار أن من لم تبلغه رسالة الإسلام أصلًا، أو بلغته مشوَّهة جدًا بحيث لا يتعرّف على حقيقتها، لا يُحكَم عليه بنفس حكم من أعرض عنها عنادًا بعد وضوح الحجة عليه — وأن أمر هؤلاء موكول لعدل الله ورحمته يوم القيامة بصورة لا يعلم تفصيلها إلا هو سبحانه. هذا لا يعني إلغاء مركزية الإيمان بالله ورسوله في التصور الإسلامي للنجاة (فهذا أصل عقدي ثابت)، لكنه يعني رفض الصورة المبسَّطة الظالمة التي تتخيّل أن كل غير مسلم في التاريخ، بصرف النظر التام عن ظرفه ومدى وصول الرسالة إليه بوضوح، مصيره واحد جامد بلا اعتبار لعدل الله ورحمته الواسعة وعلمه بكل ظرف فردي دقيق. الحكم على مصير أي فرد بعينه، مسلمًا كان أو غير مسلم، ليس لأي بشر أصلًا، ويُترَك لله وحده.',
'مغالطة شائعة: اختزال موقف الإسلام كله في جملة واحدة جامدة "كل غير مسلم في النار"، متجاهلة تمامًا هذا التفصيل الفقهي المعتبر حول أهل الفترة ومن في حكمهم، وهو تفصيل موجود فعلًا في التراث الفقهي المعتبر لا اختراعًا دفاعيًا حديثًا.',
'مبحث "أهل الفترة" ناقشه علماء أصول كبار عبر قرون (منهم ابن تيمية وابن القيم في مواضع من كتبهما)، وهو جزء أصيل من تراث الفقه الإسلامي في العقيدة، لا محاولة تلطيف معاصرة كما يُظَن أحيانًا.',
'[{"type":"quran","ref":"الإسراء: ١٥","text":"وَمَا كُنَّا مُعَذِّبِينَ حَتَّىٰ نَبْعَثَ رَسُولًا"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"أليس هذا مجرد تلطيف حديث لموقف أشد صرامة تاريخيًا؟","response":"لا، فمسألة أهل الفترة ونحوهم مبحث فقهي قديم موثَّق في كتب أصول الفقه والعقيدة عبر قرون، لا اختراعًا معاصرًا؛ لكن من الأمانة الإقرار بوجود تفاوت اجتهادي حقيقي بين العلماء في تفاصيل هذه المسألة تحديدًا، وهي مسألة تستحق نقاشًا مباشرًا مع داعية أو عالم متخصص لمن أراد تفصيلًا أعمق."}]'::jsonb,
'مصير غير المسلمين مسألة أدق وأكثر تفصيلًا فقهيًا مما توحي به الصورة المختزلة الشائعة، والحكم النهائي على أي فرد بعينه متروك لعدل الله ورحمته وعلمه الكامل بظرفه، لا لاجتهاد بشري قاطع.',
'draft', false)
